        pub async fn upsert_full_sync_address(
            &self,
            target: FullSyncTarget,
        ) -> Result<(), DatabaseError> {
            use surrealdb_types::Value;
            let _: Vec<Value> = self
                .db
                .upsert(FullSyncTarget::TABLE_NAME)
                .content(target)
                .await?;
            Ok(())
        }
        pub async fn remove_full_sync_address(
            &self,
            pub_key: PublicKey,
        ) -> Result<(), DatabaseError> {
            use surrealdb_types::{RecordId, Value};
            let _: Option<Value> = self
                .db
                .delete(RecordId::new(FullSyncTarget::TABLE_NAME, pub_key.to_base64()))
                .await?;
            Ok(())
        }
        pub async fn full_sync_addresses(
            &self,
        ) -> Result<Vec<FullSyncTarget>, DatabaseError> {
            let addresses: Vec<FullSyncTarget> = self
                .db
                .select(FullSyncTarget::TABLE_NAME)
                .await?;
            Ok(addresses)
        }
