                impl AkarekoProtocolCommandHandler for SyncEvents {
                    async fn handle<
                        S: tokio::io::AsyncRead + tokio::io::AsyncWrite + Unpin + Send,
                    >(stream: &mut S, state: &ServerState, _: &I2PAddress) {
                        let req = SyncEventsRequest::decode(stream).await.unwrap();
                        let events = match filter_events(
                                req.timestamp,
                                req.filter,
                                &state.repositories.db,
                            )
                            .await
                        {
                            Ok(events) => events,
                            Err(_) => {
                                AkarekoProtocolResponse::<
                                    (),
                                    (),
                                >::internal_error("Database Error".into())
                                    .encode(stream)
                                    .await
                                    .unwrap();
                                return;
                            }
                        };
                        let decode_streams = events
                            .iter()
                            .filter_map(|e| {
                                if e.0 == EventType::Invalid {
                                    None
                                } else {
                                    Some((e.0, e.1.len() as u64))
                                }
                            })
                            .collect();
                        AkarekoProtocolResponse::<
                            SyncEventsResponse,
                        >::ok(SyncEventsResponse {
                                decode_streams,
                                timestamp: Timestamp::now(),
                            })
                            .encode(stream)
                            .await
                            .unwrap();
                        for (event_type, topics) in events {
                            match event_type {
                                EventType::Invalid => {
                                    ::core::panicking::panic(
                                        "internal error: entered unreachable code",
                                    )
                                }
                                EventType::User => {
                                    let keys = topics
                                        .into_iter()
                                        .map(|v| unsafe {
                                            let bytes = v.to_inner()[..32].try_into().unwrap();
                                            PublicKey::from_bytes_unchecked(bytes)
                                        })
                                        .collect();
                                    let users = state
                                        .repositories
                                        .user()
                                        .get_users(keys)
                                        .await
                                        .unwrap();
                                    for user in users {
                                        user.encode(stream).await.unwrap();
                                    }
                                }
                                EventType::Manga => {
                                    let hashes = topics
                                        .into_iter()
                                        .map(|v| Hash::new(v.to_inner()))
                                        .collect::<Vec<_>>();
                                    let indexes = state
                                        .repositories
                                        .index()
                                        .get_indexes::<MangaTag>(&hashes)
                                        .await
                                        .unwrap();
                                    for index in indexes {
                                        index.encode(stream).await.unwrap();
                                    }
                                }
                                EventType::MangaContent => {
                                    let signatures = topics
                                        .into_iter()
                                        .map(|v| unsafe {
                                            Signature::from_bytes_unchecked(v.to_inner())
                                        })
                                        .collect::<Vec<_>>();
                                    let contents = state
                                        .repositories
                                        .index()
                                        .get_contents::<MangaTag>(&signatures)
                                        .await
                                        .unwrap();
                                    for content in contents {
                                        content.encode(stream).await.unwrap();
                                    }
                                }
                                EventType::Post => {
                                    let signatures = topics
                                        .into_iter()
                                        .map(|v| unsafe {
                                            Signature::from_bytes_unchecked(v.to_inner())
                                        })
                                        .collect::<Vec<_>>();
                                    let posts = state
                                        .repositories
                                        .get_posts(&signatures)
                                        .await
                                        .unwrap();
                                    for post in posts {
                                        post.encode(stream).await.unwrap();
                                    }
                                }
                            }
                        }
                    }
                }
